from flask import Flask, request, jsonify
import pickle
import os
import tempfile
import shutil
import werkzeug

app = Flask(__name__)
model_storage = {}

def secure_load_model(file_path):
    # Implement security checks here (e.g., check file type, size, etc.)
    with open(file_path, 'rb') as f:
        return pickle.load(f)

@app.route('/upload_model', methods=['POST'])
def upload_model():
    if 'model' not in request.files:
        return jsonify({'error': 'No model file provided'}), 400

    model_file = request.files['model']
    
    if model_file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if not model_file.filename.endswith('.pkl'):
        return jsonify({'error': 'File type not allowed'}), 400

    temp_dir = tempfile.mkdtemp()
    model_path = os.path.join(temp_dir, model_file.filename)
    model_file.save(model_path)

    try:
        model = secure_load_model(model_path)
        model_id = str(len(model_storage) + 1)
        model_storage[model_id] = model
        return jsonify({'model_id': model_id}), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        shutil.rmtree(temp_dir)

@app.route('/predict/<model_id>', methods=['POST'])
def predict(model_id):
    if model_id not in model_storage:
        return jsonify({'error': 'Model not found'}), 404

    input_data = request.json
    model = model_storage[model_id]

    try:
        prediction = model.predict(input_data)  # Assuming the model has a predict method
        return jsonify({'prediction': prediction.tolist()}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)